import{_ as r,o as a,c as i,a2 as s}from"./chunks/framework.Cuq8tsM6.js";const c=JSON.parse('{"title":"Gestion des Campagnes","description":"","frontmatter":{"title":"Gestion des Campagnes"},"headers":[],"relativePath":"docs/fr/faq/campaign-management.md","filePath":"docs/fr/faq/campaign-management.md"}'),t={name:"docs/fr/faq/campaign-management.md"};function o(d,e,n,p,l,u){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="gestion-des-campagnes" tabindex="-1">Gestion des Campagnes <a class="header-anchor" href="#gestion-des-campagnes" aria-label="Permalink to &quot;Gestion des Campagnes&quot;">​</a></h1><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Quel est le délai de réponse attendu ?</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"> Vous devez répondre sous <strong>48 heures ouvrées</strong>. La réactivité est la clé pour remporter les campagnes face aux autres éditeurs. Passé ce délai, getinside se réserve le droit de refuser la campagne en votre nom, et d&#39;appliquer une pénalité correspondante aux frais de plateforme prévus. </div></details><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Puis-je annuler une campagne déjà acceptée ?</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"> L&#39;annulation est fortement déconseillée. Sauf force majeure, des pénalités s&#39;appliquent pour compenser le préjudice :<br><ul><li>Pénalité forfaitaire de 250€.</li><li>+ Remboursement des frais de plateforme perdus.</li><li>+ Remboursement des frais de production (si imprimé) et de studio engagés.</li></ul></div></details><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Puis-je refuser d&#39;insérer un flyer reçu ?</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"> Oui. Vous devez vérifier la marchandise à réception. Si les supports sont endommagés ou non conformes au BAT validé (ex: marque concurrente non signalée), contactez immédiatement le support (<code>studio@getinside.fr</code>) et suspendez l&#39;insertion. </div></details><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">La campagne démarre en retard, que faire ?</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"> Si vous n&#39;avez rien distribué sur une semaine prévue : <ol><li>Saisissez &quot;0&quot; dans le reporting de la semaine.</li><li>Prévenez l&#39;annonceur via la messagerie.</li></ol> La plateforme prolongera automatiquement la campagne en fin de période pour atteindre le volume cible. </div></details><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Comment ajouter un nouveau type d&#39;offre ?</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"> Allez sur la fiche de l&#39;audience concernée et ajoutez un type de campagne. Si vous souhaitez proposer une offre sur-mesure (hors catalogue standard), sélectionnez <strong>&quot;Autre type de campagne&quot;</strong>. L&#39;équipe getinside validera ensuite la faisabilité avec vous. </div></details><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Où voir l&#39;historique de mes campagnes ?</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"><ul><li><strong>Pour les campagnes reçues (Éditeur) :</strong> Allez dans <em>Monétisation &gt; Gestionnaire de campagne</em> (Filtrez par statut : Accepté, Refusé...).</li><li><strong>Pour vos propres campagnes (Annonceur) :</strong> Allez dans <em>Campagnes &gt; Toutes les campagnes</em>.</li></ul></div></details><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Comment suivre les performances de ma campagne ?</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"> Vous disposez d&#39;un double suivi sur votre tableau de bord getinside :<br> 1. <strong>Performance (ROI) :</strong> Vous suivez les scans de vos QR codes en temps réel.<br> 2. <strong>Distribution :</strong> Les volumes de flyers insérés sont mis à jour chaque début de semaine par le distributeur (pour la semaine écoulée). </div></details>',8)])])}const g=r(t,[["render",o]]);export{c as __pageData,g as default};
